head.b:skin:
/*
-----------------------------------------------
Blogger Template Style
Name:   NewsOnly
Author: Lasantha Bandara
Author URL 1:  http://www.premiumbloggertemplates.com/
Author URL 2:  http://www.bloggertipandtrick.net/
Theme URL: http://www.premiumbloggertemplates.com/newsonly-blogger-template/
Date:   March 2015
License:  This free Blogger template is licensed under the Creative Commons Attribution 3.0 License, which permits both personal and commercial use.
However, to satisfy the 'attribution' clause of the license, you are required to keep the footer links intact which provides due credit to its authors. For more specific details about the license, you may visit the URL below:
http://creativecommons.org/licenses/by/3.0/
----------------------------------------------- */
body#layout ul{list-style-type:none;list-style:none}
body#layout ul li{list-style-type:none;list-style:none}
body#layout #myGallery{display:none}
body#layout .featuredposts{display:none}
body#layout .fp-slider{display:none}
body#layout #navcontainer{display:none}
body#layout .menu-secondary-wrap{display:none}
body#layout .menu-primary-container{display:none}
body#layout .menu-secondary-container{display:none}
body#layout #skiplinks{display:none}
body#layout .feedtwitter{display:none}
body#layout #header-wrapper {margin-bottom:10px;min-height:110px;}
body#layout .social-profiles-widget h3 {display:none;}
/* Variable definitions
====================
<Variable name="bgcolor" description="Page Background Color"
type="color" default="#fff" value="#ffffff">
<Variable name="textcolor" description="Text Color"
type="color" default="#333" value="#333333">
<Variable name="linkcolor" description="Link Color"
type="color" default="#58a" value="#5588aa">
<Variable name="pagetitlecolor" description="Blog Title Color"
type="color" default="#666" value="#cc6600">
<Variable name="descriptioncolor" description="Blog Description Color"
type="color" default="#999" value="#999999">
<Variable name="titlecolor" description="Post Title Color"
type="color" default="#c60" value="#cc6600">
<Variable name="bordercolor" description="Border Color"
type="color" default="#ccc" value="#cccccc">
<Variable name="sidebarcolor" description="Sidebar Title Color"
type="color" default="#999" value="#999999">
<Variable name="sidebartextcolor" description="Sidebar Text Color"
type="color" default="#666" value="#666666">
<Variable name="visitedlinkcolor" description="Visited Link Color"
type="color" default="#999" value="#999999">
<Variable name="bodyfont" description="Text Font"
type="font" default="normal normal 100% Georgia, Serif" value="normal normal 100% Georgia, Serif">
<Variable name="headerfont" description="Sidebar Title Font"
type="font"
default="normal normal 78% 'Trebuchet MS',Trebuchet,Arial,Verdana,Sans-serif" value="normal normal 78% &#39;Trebuchet MS&#39;,Trebuchet,Arial,Verdana,Sans-serif">
<Variable name="pagetitlefont" description="Blog Title Font"
type="font"
default="normal normal 200% Georgia, Serif" value="normal normal 200% Georgia, Serif">
<Variable name="descriptionfont" description="Blog Description Font"
type="font"
default="normal normal 78% 'Trebuchet MS', Trebuchet, Arial, Verdana, Sans-serif" value="normal normal 78% &#39;Trebuchet MS&#39;, Trebuchet, Arial, Verdana, Sans-serif">
<Variable name="postfooterfont" description="Post Footer Font"
type="font"
default="normal normal 78% 'Trebuchet MS', Trebuchet, Arial, Verdana, Sans-serif" value="normal normal 78% &#39;Trebuchet MS&#39;, Trebuchet, Arial, Verdana, Sans-serif">
<Variable name="startSide" description="Side where text starts in blog language"
type="automatic" default="left">
<Variable name="endSide" description="Side where text ends in blog language"
type="automatic" default="right">
*/
/* Use this with templates/template-twocol.html */
body{background:url('http://4.bp.blogspot.com/-AJk7r-3tJ5I/VQjKoTGeIqI/AAAAAAAALpk/5HiP7FGsCKE/s1600/background.png');color:#555555;font-family: 'Trebuchet MS', Arial, Helvetica, Sans-serif;font-size: 13px;line-height:1.4;margin:0px;padding:0px;}
a:link,a:visited{color:#0496DA;text-decoration:none;outline:none;}
a:hover{color:#23B9F7;text-decoration:none;outline:none;}
a img{border-width:0}
#body-wrapper{margin:0px;padding:0px;}
.section, .widget {margin:0px;padding:0px;line-height: 1.4;}
.widget ul, .widget li {margin:0px;padding:0px;line-height: 1.3;}
/* Header-----------------------------------------------*/
#header-wrapper{width:960px;margin:0px auto 0px;height:67px;padding:20px 0px 20px 0px;overflow:hidden;}
#header-inner{background-position:center;margin-left:auto;margin-right:auto}
#header{margin:0;padding:0;border:0 solid #cccccc;color:#424242;float:left;width:46%;overflow:hidden;}
#header h1{color:#424242;text-shadow:0px 1px 0px #fff;margin:0 5px 0 0px;padding:0px 0px 0px 15px;font-family:Oswald,Arial,Helvetica,Sans-serif;font-weight:normal;font-size:24px;line-height:26px;}
#header .description{padding-left:15px;color:#424242;text-shadow:0px 1px 0px #fff;line-height:13px;font-size:13px;padding-top:0px;margin-top:5px;font-family:'Trebuchet MS',Arial,Helvetica,Sans-serif;}
#header h1 a,#header h1 a:visited{color:#424242;text-decoration:none}
#header h2{padding-left:5px;color:#424242;font:14px Arial,Helvetica,Sans-serif}
#header2{float:right;width:52%;margin:0;padding:0;overflow:hidden;}
#header2 .widget{padding:0px 15px 0px 0px;float:right;}
.social-profiles-widget img{margin:0 4px 0 0}
.social-profiles-widget img:hover{opacity:0.8}
#top-social-profiles{padding-top:8px;padding-right:0px;height:32px;text-align:right}
#top-social-profiles img{margin:0 0 0 6px !important}
#top-social-profiles img:hover{opacity:0.8}
#top-social-profiles .widget-container{background:none;padding:0;border:0}
/* Outer-Wrapper----------------------------------------------- */
#outer-wrapper{width:960px;margin:10px auto 0px;padding:0px;text-align:left;background:#fff;-webkit-box-shadow:0 0 10px 5px #E2E2E1;-moz-box-shadow:0 0 10px 5px #E2E2E1;box-shadow:0 0 10px 5px #E2E2E1;}
#content-wrapper{padding:15px;background:#fff;overflow:hidden;}
#main-wrapper{width:460px;margin:0px 0px 0px 0px;;padding:0px;float:left;word-wrap:break-word;overflow:hidden;}
#lsidebar-wrapper{width:160px;float:left;margin:0px 13px 0px 0px;padding:0px;word-wrap:break-word;overflow:hidden;}
#rsidebar-wrapper{width:280px;float:right;margin:0px 0px 0px 15px;padding:0px;word-wrap:break-word;overflow:hidden;}
/* Headings----------------------------------------------- */
h2{}
/* Posts-----------------------------------------------*/
h2.date-header{margin:1.5em 0 .5em;display:none;}
.wrapfullpost{}
.post{margin-bottom:15px;border:0px solid #82C459;}
.post-title{color:#333333;margin:0 0 10px 0;padding:0;font-family:'Oswald', sans-serif;font-size:20px;line-height:20px;font-weight:normal;}
.post-title a,.post-title a:visited,.post-title strong{display:block;text-decoration:none;color:#333333;text-decoration:none;}
.post-title strong,.post-title a:hover{color:#0395DA;text-decoration:none;}
.post-body{margin:0px;padding:0px 0px 0px 0px;font-size:13px;line-height: 20px;}
.post-footer{margin:5px 0;}
.comment-link{margin-left:.6em}
.post-body img{padding:4px;}
.pbtthumbimg {float:left;margin:0px 10px 2px 0px;padding:5px !important;border:1px solid #eee;background:none;width:160px;height:auto;}
.postmeta-primary{color:#999;font-size:13px;line-height:18px;padding:0 0 10px}
.postmeta-secondary{color:#999;font-size:13px;line-height:18px;padding:0 0 10px}
.postmeta-primary span,.postmeta-secondary span{background-position:left center;background-repeat:no-repeat}
.meta_date{background-image:url(http://3.bp.blogspot.com/-DKl5COjDF2A/U-bAl8CuonI/AAAAAAAAM1g/Odv6rj_Zd04/s1600/date.png);padding:3px 10px 3px 20px;}
.meta_author{background-image:url(http://2.bp.blogspot.com/-r6yiecDhDQc/U-bAg8qD57I/AAAAAAAAM1M/5aMMIZVhfSE/s1600/author.png);padding:3px 10px 3px 20px;}
.meta_comments{background-image:url(http://2.bp.blogspot.com/-XPl9ybKBvg4/U-bAlkiZDYI/AAAAAAAAM1c/s_C6CwcDTkA/s1600/comments.png);padding:3px 10px 3px 20px;}
.meta_edit{background-image:url(images/edit.png);padding:3px 10px 3px 20px;}
.meta_categories{background-image:url(http://4.bp.blogspot.com/-8dOB7J7puR8/U-bAg-xkycI/AAAAAAAAM1Q/Qj72nYcfJ7k/s1600/category.png);padding:3px 10px 3px 20px;}
.meta_tags{background-image:url(http://2.bp.blogspot.com/-xMmbQP8hHWo/U-bAq4QJ51I/AAAAAAAAM3A/_fzydcCZsls/s1600/tags.png);padding:3px 10px 3px 20px;}
.readmore{margin-bottom:5px;float:right}
.readmore a{color:#0E99DA;background:#ECECEC;padding:8px 14px;font-size:12px;line-height:12px;display:inline-block;text-decoration:none;text-transform:none}
.readmore a:hover{color:#FFF;background:#0E99DA;text-decoration:none}
/* Sidebar Content----------------------------------------------- */
.sidebar{margin:0 0 10px 0;font-size:13px;color:#3E3D3D;}
.sidebar a{text-decoration:none;color:#3E3D3D;}
.sidebar a:hover{text-decoration:none;color:#0496DA;}
.sidebar h2, h3.widgettitle{border-bottom:2px solid #0E99DA;margin:0 0 10px;padding:10px 0 6px 2px;color:#414445;font-size:16px;line-height:16px;font-family:'Oswald',sans-serif;font-weight:normal;text-decoration:none;text-transform:none;}
.sidebar ul{list-style-type:none;list-style:none;margin:0px;padding:0px;}
.sidebar ul li{padding:0 0 6px 12px;margin:0 0 6px;background:url(http://4.bp.blogspot.com/-axAjQdj5Cuo/VQjKuiAH0WI/AAAAAAAALrA/ZTkDXwWton8/s1600/widget-list.png) left 7px no-repeat;}
.sidebar .widget{margin:0 0 15px 0;padding:0;color:#3E3D3D;font-size:13px;}
.main .widget{margin:0 0 5px;padding:0 0 2px}
.main .Blog{border-bottom-width:0}
.widget-container{list-style-type:none;list-style:none;margin:0 0 15px 0;padding:0;color:#3E3D3D;font-size:13px}
/* FOOTER ----------------------------------------------- */
#footer-container{}
#footer{margin-bottom:15px}
#copyrights{color:#434141;background:#EEE;text-align:center;padding:20px 0;border-top:1px solid #E0E0E0;border-bottom:1px solid #E0E0E0}
#copyrights a{color:#434141}
#copyrights a:hover{color:#434141;text-decoration:none}
#credits{color:#7D7D7D;text-align:center;font-size:11px;padding:10px 0}
#credits a{color:#7D7D7D;text-decoration:none}
#credits a:hover{text-decoration:none;color:#7D7D7D}
#footer-widgets-container{}
#footer-widgets{background:#FFF;padding:20px 0 0;border-top:2px solid #ECECEC}
.footer-widget-box{width:225px;float:left;margin-left:12px}
.footer-widget-box-last{}
#footer-widgets .widget-container{color:#3E3D3D;border: none;padding: 0;background: none;}
#footer-widgets .widget-container a{color:#3E3D3D;text-decoration:none}
#footer-widgets .widget-container a:hover{color:#0496DA;text-decoration:none}
#footer-widgets h2{border-bottom:2px solid #0E99DA;margin:0 0 10px;padding:10px 0 6px 2px;color:#414445;font-size:16px;line-height:16px;font-family:'Oswald',sans-serif;font-weight:normal;text-decoration:none;text-transform:none;}
#footer-widgets .widget ul{list-style-type:none;list-style:none;margin:0px;padding:0px;}
#footer-widgets .widget ul li{padding:0 0 6px 12px;margin:0 0 6px;background:url(http://4.bp.blogspot.com/-axAjQdj5Cuo/VQjKuiAH0WI/AAAAAAAALrA/ZTkDXwWton8/s1600/widget-list.png) left 7px no-repeat;}
.footersec {}
.footersec .widget{margin:0 0 15px 0;padding:0;color:#3E3D3D;font-size:13px;}
.footersec ul{}
.footersec ul li{}
/* Search ----------------------------------------------- */
#search{border:1px solid #D8D8D8;background:#fff url(http://1.bp.blogspot.com/-D9ZEVGNcyNY/VQjKtfoLZgI/AAAAAAAALq0/y2E3SiRDmt0/s1600/search.png) 99% 50% no-repeat;text-align:left;padding:6px 24px 6px 6px}
#search #s{background:none;color:#979797;border:0;width:100%;padding:0;margin:0;outline:none}
#content-search{width:300px;padding:15px 0}
#topsearch{float:right;margin-top:15px}
#topsearch #s{width:220px}
/* Comments----------------------------------------------- */
#comments{margin-bottom:15px;border:0px solid #82C459;padding:10px}
#comments h4{font-size:16px;font-weight:bold;margin:1em 0;}
#comments-block3{padding:0;margin:0;float:left;overflow:hidden;position:relative;}
#comment-name-url{width:465px;float:left}
#comment-date{width:465px;float:left;margin-top:5px;font-size:10px;}
#comment-header{float:left;padding:5px 0 40px 10px;margin:5px 0px 15px 0px;position:relative;background-color:#fff;border:1px dashed #ddd;}
a.comments-autor-name{color:#000;font:normal bold 14px Arial,Tahoma,Verdana}
a.says{color:#000;font:normal 14px Arial,Tahoma,Verdana}
.says a:hover{text-decoration:none}
.deleted-comment{font-style:italic;color:gray}
#blog-pager-newer-link{float:left}
#blog-pager-older-link{float:right}
#blog-pager{text-align:center;margin:10px 0 0 5px;}
.feed-links{clear:both;line-height:2.5em}
.pbtsharethisbutt{overflow:hidden;padding:5px 0;margin:0;font-size:12px;text-transform:uppercase;float:left;}
.pbtsharethisbutt a {padding-left:5px;padding-right:5px;}
/* Profile ----------------------------------------------- */
.author-profile {background:#f6f6f6;border:1px solid #eee;margin:5px 0 10px 0;padding:8px;overflow:hidden;}
.author-profile img {border:1px solid #ddd;float:left;margin-right:10px;}
.post-iconspbt {margin:5px 0 0 0;padding:0px;}
.post-locationpbt {margin:5px 0;padding:0px;}
#navbar-iframe{height:0;visibility:hidden;display:none;}
.breadcrumb-bwrap {border: 1px dotted #ddd;line-height: 1.4;margin: 0 0 15px;padding: 5px;}
.separator a[style="margin-left: 1em; margin-right: 1em;"] {margin-left: auto!important;margin-right: auto!important;}
.separator a[style="clear: left; float: left; margin-bottom: 1em; margin-right: 1em;"] {clear: none !important; float: none !important; margin-bottom: 0em !important; margin-right: 0em !important;}
.separator a[style="clear: left; float: left; margin-bottom: 1em; margin-right: 1em;"] img {float: left !important; margin: 0px 10px 10px 0px;}
.separator a[style="clear: right; float: right; margin-bottom: 1em; margin-left: 1em;"] {clear: none !important; float: none !important; margin-bottom: 0em !important; margin-left: 0em !important;}
.separator a[style="clear: right; float: right; margin-bottom: 1em; margin-left: 1em;"] img {float: right !important; margin: 0px 0px 10px 10px;}


/* 사용자 정의 포스팅 제목 크기 */

/* h1 태그 (가장 큰 제목) */
.post-body h1 {
  font-size: 24px !important; /* 원하는 크기로 변경 (예: 24px) */
  line-height: 1.4em; /* 줄 간격도 함께 조정하여 가독성을 높일 수 있습니다. */
}

/* h2 태그 (중간 제목) */
.post-body h2 {
  font-size: 22px !important; /* 원하는 크기로 변경 (예: 20px) */
  line-height: 1.5em;
}

/* h3 태그 (작은 제목) */
.post-body h3 {
  font-size: 20px !important; /* 원하는 크기로 변경 (예: 18px) */
  line-height: 1.6em;
}

.post-body p, .post-body div {
  font-size: 17px !important;
  line-height: 1.7;
}

@media (max-width: 768px) {
  .post-body p, .post-body div {
    font-size: 15px !important;
    line-height: 1.6;
  }
}



/* =================================================
   본문 조금 넓히기 + 좌우 사이드바 균형 완벽 조정
   ================================================= */

/* 전체 레이아웃 폭 (깨지지 않게 1080px로 설정) */
#outer-wrapper {
    width: 1080px !important;
    max-width: 1080px !important;
}

/* 본문 폭 : 590px (원래 460px → 160px만 넓힘) */
#main-wrapper {
    width: 599px !important;
    margin: 0 15px 0 0 !important;  /* 오른쪽 여백 살짝 */
}

/* 왼쪽 사이드바 : 190px */
#lsidebar-wrapper {
    width: 190px !important;
    margin-right: 15px !important;
}

/* 오른쪽 사이드바 : 250px (원래 280px보다 좁혀서 여유 확보) */
#rsidebar-wrapper {
    width: 216px !important;
    margin-left: 15px !important;
}

/* 컨텐츠 래퍼 패딩 살짝 줄여서 더 여유롭게 */
#content-wrapper {
    padding: 10px 15px !important;
}

/* 모바일에서는 그대로 유지 (반응형) */
@media only screen and (max-width: 768px) {
    #outer-wrapper,
    #main-wrapper,
    #lsidebar-wrapper,
    #rsidebar-wrapper {
        width: 100% !important;
        margin: 0 !important;
        float: none !important;
        padding: 0 !important;
    }
}

